UPDATE public.articulos SET metadata = '{"areas": ["carácter", "corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["avanzada", "compañía", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Conocer las capacidades corporales", "Crear un ambiente de distensión", "Fomentar el desarrollo del criterio"], "materiales": ["Sin Materiales"], "variaciones": "Si no el traslado de un participante como \"jarra\" se hace complejo y hay buen clima, se puede utilizar un recipiente con agua y sin tapa para reemplazar a la \"jarra\".", "recomendaciones": "Procure evitar que los equipos hagan un exceso de fuerza, y genere equipos equilibrados en fuerzas y peso.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_carreraDeJarras.png", "objetivos_educativos": [{"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Consolidando sus valores personales, coherencia ética y toma de decisiones firmes al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla, guiando a otros con el ejemplo."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla, actuando con honestidad y espíritu de superación."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla, actuando con honestidad y espíritu de superación."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla, actuando con honestidad y espíritu de superación."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla, actuando con honestidad y espíritu de superación."}, {"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Potenciando su rendimiento psicomotor, toma de decisiones rápidas y resistencia aeróbica al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla, fomentando la autodisciplina y hábitos saludables."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla, trabajando en equipo y respetando sus límites corporales."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla, trabajando en equipo y respetando sus límites corporales."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla, trabajando en equipo y respetando sus límites corporales."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla, trabajando en equipo y respetando sus límites corporales."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Liderando iniciativas de servicio, diálogo intercultural y organización comunitaria al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla, velando por la inclusión y el bienestar colectivo."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla, fortaleciendo la convivencia democrática."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla, fortaleciendo la convivencia democrática."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla, fortaleciendo la convivencia democrática."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr en equipo sosteniendo y transportando una jarra llena de agua sin derramarla, fortaleciendo la convivencia democrática."}]}'::jsonb WHERE id = 'b9b8b49f-bca3-4e3f-bcc1-0cd35f65dbef';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad"], "lugares": ["Campo Abierto", "Exterior", "Interior"], "cantidad": "04 participantes", "duracion": "15 minutos", "unidades": ["avanzada", "compañía", "manada", "tropa"], "objetivos": ["Desarrollar la motricidad", "Desfogue de Energías"], "materiales": ["Bolsa", "Cuerda"], "variaciones": "Una variación más sencilla puede ser sin un peso y simplemente formar el círculo con la cuerda a la misma altura del piso.", "recomendaciones": "Ponga especial atención a posibles caídas que se pueden producir por golpes con el peso en la cuerda, o con la misma cuerda que se amarre en los pies de las y los jugadores al momento de saltar.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_esquivaElTiro.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Potenciando su rendimiento psicomotor, toma de decisiones rápidas y resistencia aeróbica al esquivar una pelota o cuerda con peso que gira a nivel del suelo, saltando con agilidad y coordinando el ritmo, fomentando la autodisciplina y hábitos saludables."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al esquivar una pelota o cuerda con peso que gira a nivel del suelo, saltando con agilidad y coordinando el ritmo, trabajando en equipo y respetando sus límites corporales."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al esquivar una pelota o cuerda con peso que gira a nivel del suelo, saltando con agilidad y coordinando el ritmo, trabajando en equipo y respetando sus límites corporales."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al esquivar una pelota o cuerda con peso que gira a nivel del suelo, saltando con agilidad y coordinando el ritmo, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "5d2d48ed-c461-4a8e-9048-cceecd3de2e2", "area": "Corporalidad", "texto": "Me gusta jugar con otros niños y niñas y respeto las reglas de los juegos.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al esquivar una pelota o cuerda con peso que gira a nivel del suelo, saltando con agilidad y coordinando el ritmo, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al esquivar una pelota o cuerda con peso que gira a nivel del suelo, saltando con agilidad y coordinando el ritmo, trabajando en equipo y respetando sus límites corporales."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al esquivar una pelota o cuerda con peso que gira a nivel del suelo, saltando con agilidad y coordinando el ritmo, trabajando en equipo y respetando sus límites corporales."}]}'::jsonb WHERE id = 'f4373764-4b71-4f03-b768-1e16316c9b13';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Exterior"], "cantidad": "12 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Refuerzo de habilidades físicas", "Trabajo en equipo"], "materiales": ["Sin Materiales"], "variaciones": "", "recomendaciones": "", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_carreraDelTunel.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Potenciando su rendimiento psicomotor, toma de decisiones rápidas y resistencia aeróbica al pasar por debajo del túnel formado por las piernas de los compañeros de equipo para avanzar en relevos, fomentando la autodisciplina y hábitos saludables."}, {"id": "106e27af-ec7a-45fa-9295-fcef88fbef3d", "area": "Corporalidad", "texto": "Convivo constantemente en la naturaleza y participo en actividades deportivas y recreativas.", "unidad": "Clan", "como_se_cumple": "Consolidando el dominio y autocontrol corporal, evaluando sus límites físicos e impulsos al pasar por debajo del túnel formado por las piernas de los compañeros de equipo para avanzar en relevos con un sentido de superación constante."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al pasar por debajo del túnel formado por las piernas de los compañeros de equipo