UPDATE public.articulos SET metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Exterior", "Interior", "Sala"], "cantidad": "02 participantes", "duracion": "20 minutos", "unidades": ["compañía", "tropa", "avanzada", "clan"], "objetivos": ["Estimular la creatividad", "Trabajo en equipo"], "materiales": ["Cinta Adhesiva", "Lápiz", "Papel"], "variaciones": "Las y los personajes pueden variar por diversas temáticas, por ejemplo, se pueden usar sólo personajes de la historia del movimiento para reforzar conocimiento sobre historia, o puede colocar nombres de canciones y para descifrar la canción le deben cantar una estrofa de la canción. O entregar la información con mímicas, etc.", "recomendaciones": "Utilice personajes conocidos para los participantes, no dificulte los personajes es una dinámica para pasar un buen rato y reforzar las relaciones entre niños, niñas y jóvenes.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_DinamicaQuienCuentaMiHistoria.png", "objetivos_educativos": [{"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no para superar los desafíos técnicos de la dinámica."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no para superar los desafíos técnicos de la dinámica."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no para superar los desafíos técnicos de la dinámica."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no para superar los desafíos técnicos de la dinámica."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando su agilidad mental, pensamiento crítico y capacidad de innovación al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no, liderando la resolución del problema."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Diseñando estrategias complejas y adaptativas con plena autonomía al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no, demostrando versatilidad y madurez intelectual."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no, fortaleciendo la convivencia democrática."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no, fortaleciendo la convivencia democrática."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no, fortaleciendo la convivencia democrática."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no, fortaleciendo la convivencia democrática."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Liderando iniciativas de servicio, diálogo intercultural y organización comunitaria al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no, velando por la inclusión y el bienestar colectivo."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo el servicio social, la justicia y la construcción de ciudadanía activa al adivinar y relatar anécdotas o identidades secretas de personajes a través de preguntas de sí o no, asumiendo un rol proactivo en su comunidad."}]}'::jsonb WHERE id = '53cbdb8e-ffce-413b-bb9a-601fd070dc07';
