UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "06 participantes", "duracion": "20 minutos", "unidades": ["manada", "compañía", "tropa", "avanzada"], "objetivos": ["Estimular la creatividad", "Reforzar el conocimiento del cuerpo", "Trabajo en equipo"], "materiales": ["Listado de temas"], "variaciones": "Puede agregar una variable tiempo a cada cuadro, indicando un tiempo determinado para que puedan hacer la representación, de igual manera puede efectuar la actividad simplemente gritando lo que tienen que representar y gana el punto el equipo que primero completa el cuadro.", "recomendaciones": "Procure hacer énfasis en el respeto del cuerpo y los espacios personales", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_DinamicaCuadrosPlasticos.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al representar escenas estáticas o corporales creativas con su patrulla según la temática asignada, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al representar escenas estáticas o corporales creativas con su patrulla según la temática asignada, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}