UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "cantidad": "04 participantes", "duracion": "15 minutos", "unidades": ["manada", "compañía", "tropa", "avanzada", "clan"], "objetivos": ["Estrategia y planificación", "Trabajo en equipo"], "materiales": ["Lápiz", "Papel", "Pañolin", "Silbato"], "variaciones": "Las variaciones pueden ser debido al tipo de fichas que se utilicen, otra variación puede ser que cada partida que ganen tengan que hacer el sonido de un gato.", "recomendaciones": "Procure poner atención al momento de las llegadas al tablero para evitar roces por discusiones sobre quien se ubicó primero en que lugar.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_JuegoDelGatoScout.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica, trabajando en equipo y respetando sus límites corporales."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica, trabajando en equipo y respetando sus límites corporales."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica, trabajando en equipo y respetando sus límites corporales."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica, trabajando en equipo y respetando sus límites corporales."}, {"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Potenciando su rendimiento psicomotor, toma de decisiones rápidas y resistencia aeróbica al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica, fomentando la autodisciplina y hábitos saludables."}, {"id": "69fff91f-a493-483d-92d6-8319700236c2", "area": "Corporalidad", "texto": "Conozco los procesos biológicos que regulan mi organismo, protejo mi salud, acepto mis posibilidades físicas y oriento mis impulsos y fuerzas.", "unidad": "Clan", "como_se_cumple": "Consolidando el dominio y autocontrol corporal, evaluando sus límites físicos e impulsos al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica con un sentido de superación constante."}, {"id": "ec280dd0-2d80-4b84-86ad-2d362da14886", "area": "Creatividad", "texto": "Me gusta participar en juegos de observación.", "unidad": "Manada", "como_se_cumple": "Estimulando su imaginación y pensamiento lúdico al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica para resolver situaciones sencillas de forma creativa."}, {"id": "418f2b77-f15b-405a-95bd-8033c0b6a4c2", "area": "Creatividad", "texto": "Puedo contar con detalles las anécdotas y aventuras que hemos tenido en la Manada.", "unidad": "Manada", "como_se_cumple": "Estimulando su imaginación y pensamiento lúdico al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica para resolver situaciones sencillas de forma creativa."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica para superar los desafíos técnicos de la dinámica."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica para superar los desafíos técnicos de la dinámica."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica para superar los desafíos técnicos de la dinámica."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica para superar los desafíos técnicos de la dinámica."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando su agilidad mental, pensamiento crítico y capacidad de innovación al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica, liderando la resolución del problema."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Diseñando estrategias complejas y adaptativas con plena autonomía al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica, demostrando versatilidad y madurez intelectual."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica con sus compañeros de seisena."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica, fortaleciendo la convivencia democrática."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica, fortaleciendo la convivencia democrática."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica, fortaleciendo la convivencia democrática."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica, fortaleciendo la convivencia democrática."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Liderando iniciativas de servicio, diálogo intercultural y organización comunitaria al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica, velando por la inclusión y el bienestar colectivo."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo el servicio social, la justicia y la construcción de ciudadanía activa al correr por turnos para posicionar pañolines en un tablero de tres en línea gigante de forma estratégica, asumiendo un rol proactivo en su comunidad."}]}'::jsonb WHERE id = 'cf0fce88-68dd-40ab-9a65-d684c9c28edd';
UPDATE public.articulos SET metadata = '{"areas": ["carácter", "creatividad", "sociabilidad"], "lugares": ["Exterior", "Interior", "Sala"], "cantidad": "04 participantes", "duracion": "30 minutos", "unidades": ["avanzada", "clan", "compañía", "manada", "tropa"], "objetivos": ["Desarrollar la capacidad cognitiva", "Estimular la agilidad", "Estimular la agilidad mental"], "materiales": ["Dados", "Guantes de cocina", "Regalos envueltos"], "variaciones": "Una variación puede ser hacer lo mismo con los ojos vendados, mientras que la o el jugador que le seguiría en turno le indica el resultado de los dados.", "recomendaciones": "El o la moderadora debe estar atento a que los jugadores no lancen los dados más de una vez o indique un resultado que no corresponde para tener el regalo antes de tiempo.\r\n\r\nDe la misma manera se debe poner especial atención en la forma en que se entregan los regalos y guantes de un jugador a otro, debe ser rápido pero con precaución de que no haya un golpe.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_regalosYGuantes.png", "objetivos_educativos": [{"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Consolidando sus valores personales, coherencia ética y toma de decisiones firmes al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno, guiando a otros con el ejemplo."}, {"id": "770a8ff3-7bb8-45dd-b114-5ae1069eff62", "area": "Carácter", "texto": "Actúo consecuentemente con los valores que me inspiran.", "unidad": "Clan", "como_se_cumple": "Autoevaluando su coherencia de vida y templanza ante la presión al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno, reafirmando su compromiso con su proyecto personal y la Ley Scout."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno, actuando con honestidad y espíritu de superación."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno, actuando con honestidad y espíritu de superación."}, {"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Asumiendo con alegría su rol en el juego al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno, aprendiendo a esforzarse por el grupo y a aceptar los resultados."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Asumiendo con alegría su rol en el juego al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno, aprendiendo a esforzarse por el grupo y a aceptar los resultados."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_