UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "08 participantes", "duracion": "20 minutos", "unidades": ["manada", "compañía", "tropa"], "objetivos": ["Aprender a seguir instrucciones", "Estimular la confianza", "Trabajo en equipo"], "materiales": ["Pañolin"], "variaciones": "Puede permitir que los submarinos se hundan entre sí para evitar que lleguen a sus metas, para destruir a otro submarino puede chocarlo por un costado o hacer que se separen, también puede hacer que el primer jugador de la fila se convierta en un torpedo que se lanza con una señal determinada y si choca al otro submarino lo hunde.\r\n\r\nPuede hacer que la meta no sea un punto fijo para dificultar la llegada y que se mueva cada cierto tiempo, también puede hacer que los puntos de origen y destino de cada submarino sean diferentes y obligue a que se crucen entre equipos en el camino.", "recomendaciones": "Procure usar un terreno homogéneo y parejo para evitar accidentes por caídas.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeSubmarinos.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador, trabajando en equipo y respetando sus límites corporales."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador, trabajando en equipo y respetando sus límites corporales."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del último jugador, trabajando en equipo y respetando sus límites corporales."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al desplazarse en fila con los ojos vendados guiados únicamente por las señales táctiles del últi