UPDATE public.articulos SET metadata = '{"areas": ["carácter", "sociabilidad"], "lugares": ["Exterior", "Interior"], "cantidad": "02 participantes", "duracion": "30 minutos", "unidades": ["manada", "compañía", "tropa", "avanzada", "clan"], "objetivos": ["Aprendizaje por la acción", "Estimular la participación", "Reforzar el valor de la democracia", "Toma de Decisiones"], "materiales": ["Dinero Falso", "Listado de Actividades", "Papel", "Plumón"], "variaciones": "<ul>\r\n \t<li>Se puede permitir a los participantes invertir su dinero en una sola actividad o distribuirlo entre varias propuestas.</li>\r\n \t<li>También se puede establecer un límite de inversión para evitar que un solo miembro domine el proceso de votación.</li>\r\n \t<li>Otra variación es realizar una actividad previa donde puedan ganar y perder dinero mediante un juego simple para añadir una dificultad económica, aunque esto no es recomendable al hacerlo como un juego democrático.</li>\r\n</ul>", "recomendaciones": "Se claro al momento de establecer las reglas de la dinámica de esta manera se evitan conflictos en los equipos.", "justificacion_areas": "Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_JuegoDemocraticoLosInversionistas.png", "objetivos_educativos": [{"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Asumiendo con alegría su rol en el juego al negociar y tomar decisiones de inversión simuladas analizando el riesgo y el beneficio colectivo, aprendiendo a esforzarse por el grupo y a aceptar los resultados."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Asumiendo con alegría su rol en el juego al negociar y tomar decisiones de inversión simuladas analizando el riesgo y el beneficio colectivo, aprendiendo a esforzarse por el grupo y a aceptar los resultados."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al negociar y tomar decisiones de inversión simuladas analizando el riesgo y el beneficio colectivo, actuando con honestidad y espíritu de superación."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al negociar y tomar decisiones de inversión simuladas analizando el riesgo y el beneficio colectivo, actuando con honestidad y espíritu de superación."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al negociar y tomar decisiones de inversión simuladas analizando el riesgo y el beneficio colectivo, actuando con honestidad y espíritu de superación."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al negociar y tomar decisiones de inversión simuladas analizando el riesgo y el beneficio colectivo, actuando con honestidad y espíritu de superación."}, {"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Consolidando sus valores personales, coherencia ética y toma de decisiones firmes al negociar y tomar decisiones de inversión simuladas analizando el riesgo y el beneficio colectivo, guiando a otros con el ejemplo."}, {"id": "770a8ff3-7bb8-45dd-b114-5ae1069eff62", "area": "Carácter", "texto": "Actúo consecuentemente con los valores que me inspiran.", "unidad": "Clan", "como_se_cumple": "Autoevaluando su coherencia de vida y templanza ante la presión al negociar y tomar decisiones de inversión simuladas analizando el riesgo y el beneficio colectivo, reafirmando su compromiso con su proyecto personal y la Ley Scout."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al negociar y tomar decisiones de inversión simuladas analizando el riesgo y el beneficio colectivo con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al negociar y tomar decisiones de inversión simuladas analizando el riesgo y el beneficio colectivo con sus compañeros de seisena."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al negociar y tomar decisiones de inversión simuladas analizando el riesgo y el beneficio colectivo, fortaleciendo la convivencia democrática."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al negociar y tomar decisiones de inversión simuladas analizando el riesgo y el beneficio colectivo, fortaleciendo la convivencia democrática."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al negociar y tomar decisiones de inversión simuladas analizando el riesgo y el beneficio colectivo, fortaleciendo la convivencia democrática."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al negociar y tomar decisiones de inversión simuladas analizando el riesgo y el beneficio colectivo, fortaleciendo la convivencia democrática."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Liderando iniciativas de servicio, diálogo intercultural y organización comunitaria al negociar y tomar decisiones de inversión simuladas analizando el riesgo y el beneficio colectivo, velando por la inclusión y el bienestar colectivo."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo el servicio social, la justicia y la construcción de ciudadanía activa al negociar y tomar decisiones de inversión simuladas analizando el riesgo y el beneficio colectivo, asumiendo un rol proactivo en su comunidad."}]}'::jsonb WHERE id = 'bddb6314-6411-404b-9107-40c9da299291';
