UPDATE public.articulos SET metadata = '{"areas": ["carácter", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior", "Interior", "Sala"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["manada", "compañía", "tropa"], "objetivos": ["Crear un ambiente de distensión", "Fomentar un entorno de confianza"], "materiales": ["Pañolin"], "variaciones": "Se puede hacer igual pero cambiando la pregunta, por ¿Eres tu el amor de mi vida¿¿, pasando los/as Dráculas a ser los/as amantes secretos.", "recomendaciones": "Puede evaluar la actividad con preguntas al final, como por ejemplo, ¿Cómo se han sentido? ¿Hubo miedo a confianza? ¿Cómo respondiste?", "justificacion_areas": "Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_EresDracula.png", "objetivos_educativos": [{"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Asumiendo con alegría su rol en el juego al desplazarse con sigilo en la oscuridad intentando descubrir quién es el vampiro oculto mediante el tacto y el sonido, aprendiendo a esforzarse por el grupo y a aceptar los resultados."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Asumiendo con alegría su rol en el juego al desplazarse con sigilo en la oscuridad intentando descubrir quién es el vampiro oculto mediante el tacto y el sonido, aprendiendo a esforzarse por el grupo y a aceptar los resultados."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al desplazarse con sigilo en la oscuridad intentando descubrir quién es el vampiro oculto mediante el tacto y el sonido, actuando con honestidad y espíritu de superación."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al desplazarse con sigilo en la oscuridad intentando descubrir quién es el vampiro oculto mediante el tacto y el sonido, actuando con honestidad y espíritu de superación."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al desplazarse con sigilo en la oscuridad intentando descubrir quién es el vampiro oculto mediante el tacto y el sonido, actuando con honestidad y espíritu de superación."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al desplazarse con sigilo en la oscuridad intentando descubrir quién es el vampiro oculto mediante el tacto y el sonido, actuando con honestidad y espíritu de superación."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al desplazarse con sigilo en la oscuridad intentando descubrir quién es el vampiro oculto mediante el tacto y el sonido con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto l