UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "06 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "compañía", "tropa"], "objetivos": ["Promover la elaboración de estrategias", "Trabajo en equipo"], "materiales": ["Pelota"], "variaciones": "Puede variar el juego indicando que la pelota sólo se puede pasar en mano o que sólo puede ser lanzada, o dando ambas opciones.", "recomendaciones": "Procure tener las precauciones con el terreno, pero también haciendo énfasis en la seguridad y en el cuidado con aquellos que sean más pequeños o tengan menos fuerza.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_elViejoTarugo.png", "objetivos_educativos": [{"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Potenciando su rendimiento psicomotor, toma de decisiones rápidas y resistencia aeróbica al correr para esquivar al cazador o tarugo en el centro del círculo mediante movimientos rápidos y giros, fomentando la autodisciplina y hábitos saludables."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr para esquivar al cazador o tarugo en el centro del círculo mediante movimientos rápidos y giros, trabajando en equipo y respetando sus límites corporales."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr para esquivar al cazador o tarugo en el centro del círculo mediante movimientos rápidos y giros, trabajando en equipo y respetando sus límites corporales."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr para esquivar al cazador o tarugo en el centro del círculo mediante movimientos rápidos y giros, trabajando en equipo y respetando sus límites corporales."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr para esquivar al cazador o tarugo en el centro del círculo mediante movimientos rápidos y giros, trabajando en equipo y respetando sus límites corporales."}, {"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayoría de los problemas técnicos domésticos simples.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando su agilidad mental, pensamiento crítico y capacidad de innovación al correr para esquivar al cazador o tarugo en el centro del círculo mediante movimientos rápidos y giros, liderando la resolución del problema."}, {"id": "103661fc-3396-4eac-9182-58b7e54d5115", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al correr para esquivar al cazador o tarugo en el centro del círculo mediante movimientos rápidos y giros para superar 