UPDATE public.articulos SET metadata = '{"areas": ["carácter", "creatividad", "sociabilidad"], "lugares": ["Bosque", "Campo delimitado", "Exterior"], "cantidad": "10 participantes", "duracion": "30 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Fomentar las relaciones interpersonales", "Promover la elaboración de estrategias", "Trabajo en equipo"], "materiales": ["Pañolin"], "variaciones": "Se puede instalar una ¿?Zona de los Dioses¿? por la que todos tendrán que pasar cada vez cuando vayan a robar y cuando vuelvan con lo robado. Para controlar el flujo de pérdida del tesoro, en esta zona se pueden jugar la pieza de tesoro con una pelea de pañolines contra el jugador.", "recomendaciones": "Procure hacer énfasis en la seguridad sobre el terreno de juego y que pisen con cuidado a la hora de desplazarse por el área de juego.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_protegiendoLasBases.png", "objetivos_educativos": [{"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Consolidando sus valores personales, coherencia ética y toma de decisiones firmes al organizar la defensa y el resguardo de zonas delimitadas contra las incursiones del equipo rival, guiando a otros con el ejemplo."}, {"id": "770a8ff3-7bb8-45dd-b114-5ae1069eff62", "area": "Carácter", "texto": "Actúo consecuentemente con los valores que me inspiran.", "unidad": "Clan", "como_se_cumple": "Autoevaluando su coherencia de vida y templanza ante la presión al organizar la defensa y el resguardo de zonas delimi