UPDATE public.articulos SET metadata = '{"areas": ["carácter", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "compañía", "manada", "tropa"], "objetivos": ["Desarrollar el carácter mediante la cooperación", "Estimular la creatividad", "Trabajo en equipo"], "materiales": "", "variaciones": "Una variación posible es cambiar sólo un trozo entre cada equipo, es decir, de la fotografía A se toma un trozo y se coloca en B, de la B se toma un trozo y se coloca en C, y así según cuantas fotografías haya.\r\n\r\nCon esta variación se busca mostrar a los participantes la interdepencia que tienen los equipos unos con otros y no es sino hasta que hablan con otro equipo que podrán resolver la situación.", "recomendaciones": "Procure dejar los trozos vueltos para abajo de forma que el trozo sacado por le participante sea más sorpresivo al ubicarlo en la restauración.\r\n\r\nDeje las reglas muy claras desde un principio, al ser un juego que promueve la creatividad, es necesario establecer el marco de trabajo general.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeLaFotografia.png", "objetivos_educativos": [{"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Consolidando sus valores personales, coherencia ética y toma de decisiones firmes al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito, guiando a otros con el ejemplo."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito, actuando con honestidad y espíritu de superación."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito, actuando con honestidad y espíritu de superación."}, {"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Asumiendo con alegría su rol en el juego al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito, aprendiendo a esforzarse por el grupo y a aceptar los resultados."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Asumiendo con alegría su rol en el juego al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito, aprendiendo a esforzarse por el grupo y a aceptar los resultados."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito, actuando con honestidad y espíritu de superación."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es i