UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Desfogue de Energías", "Refuerzo de habilidades físicas"], "materiales": ["Sin Materiales"], "variaciones": "Puede variar el juego manteniendo al equipo en unido, en este caso \"jinete\" y \"caballo\" llegarían hasta el extremo del campo y volverían, para hacer el relevo con la o el compañero que sigue.", "recomendaciones": "Procure que haya un equilibrio de fuerzas físicas entre los equipos y tenga criterio en los Relevos basándose en el peso de cada participante, evite accidentes por sobreesfuerzo físico.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_RelevosDelJinete.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Potenciando su rendimiento psicomotor, toma de decisiones rápidas y resistencia aeróbica al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada, fomentando la autodisciplina y hábitos saludables."}, {"id": "106e27af-ec7a-45fa-9295-fcef88fbef3d", "area": "Corporalidad", "texto": "Convivo constantemente en la naturaleza y participo en actividades deportivas y recreativas.", "unidad": "Clan", "como_se_cumple": "Consolidando el dominio y autocontrol corporal, evaluando sus límites físicos e impulsos al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada con un sentido de superación constante."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada, trabajando en equipo y respetando sus límites corporales."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada, trabajando en equipo y respetando sus límites corporales."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada, trabajando en equipo y respetando sus límites corporales."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada, trabajando en equipo y respetando sus límites corporales."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Liderando iniciativas de servicio, diálogo intercultural y organización comunitaria al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada, velando por la inclusión y el bienestar colectivo."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo el servicio social, la justicia y la construcción de ciudadanía activa al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada, asumiendo un rol proactivo en su comunidad."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada, fortaleciendo la convivencia democrática."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada, fortaleciendo la convivencia democrática."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr en relevos cargando a un compañero en la espalda de forma segura y coordinada, fortaleciendo la convivencia democrática."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Soc