UPDATE public.articulos SET metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "04 participantes", "duracion": "25 minutos", "unidades": ["compañía", "tropa", "avanzada", "clan"], "objetivos": ["Estimular la creatividad", "Trabajo en equipo"], "materiales": ["Bombillas", "Cinta Adhesiva", "Huevos", "Objetos Varios", "Papel craft", "Pañolin"], "variaciones": "Puede realizar la misma prueba arrojándole cosas pesadas al armazón, o variando la altura y materiales de construcción, lanzando el armazón contra algo, etc.", "recomendaciones": "Procure tener las condiciones adecuadas para la posterior limpieza en caso de ruptura de los huevos, idealmente la misma persona debe realizar la prueba de resistencia para evitar reclamos de intencionalidad.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ProtegeAlHuevo.png", "objetivos_educativos": [{"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al diseñar una estructura protectora para evitar que un huevo se rompa al ser lanzado desde una gran altura para superar los desafíos técnicos de la dinámica."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al diseñar una estructura protectora para evitar que un huevo se rompa al ser lanzado desde una gran altura para superar los desafíos técnicos de la dinámica."}, {"id": "49ae6ac6-be8f-4f2c