UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "individual", "duracion": "15 minutos", "unidades": ["avanzada", "compañía", "manada", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Conocer las capacidades corporales", "Crear un ambiente de distensión", "Desarrollar la motricidad", "Estimular la creatividad"], "materiales": ["Agua", "Vasos plásticos o de papel"], "variaciones": "Una variación puede ser obligar a mantener las manos en una parte determinada.", "recomendaciones": "Procure un área de juego que sea despejada y plana para evitar accidentes. Al mismo tiempo considere que haya buen clima para hacer la actividad.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_carreraConVasoDeAgua.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Potenciando su rendimiento psicomotor, toma de decisiones rápidas y resistencia aeróbica al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, fomentando la autodisciplina y hábitos saludables."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, trabajando en equipo y respetando sus límites corporales."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, trabajando en equipo y respetando sus límites corporales."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "5d2d48ed-c461-4a8e-9048-cceecd3de2e2", "area": "Corporalidad", "texto": "Me gusta jugar con otros niños y niñas y respeto las reglas de los juegos.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, trabajando en equipo y respetando sus límites corporales."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, trabajando en equipo y respetando sus límites corporales."}, {"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayoría de los problemas técnicos domésticos simples.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando su agilidad mental, pensamiento crítico y capacidad de innovación al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, liderando la resolución del problema."}, {"id": "103661fc-3396-4eac-9182-58b7e54d5115", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo para superar los desafíos técnicos de la dinámica."}, {"id": "0f60be94-6de3-4c34-a6ff-5b5018f0b156", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo para superar los desafíos técnicos de la dinámica."}, {"id": "8985ff05-ee84-4fba-af46-146c5374df89", "area": "Creatividad", "texto": "Participo en los talleres de manualidades que se hacen en la Manada.", "unidad": "Manada", "como_se_cumple": "Estimulando su imaginación y pensamiento lúdico al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo para resolver situaciones sencillas de forma creativa."}, {"id": "d4232b99-5655-49c6-9d24-099cfe9c8180", "area": "Creatividad", "texto": "Practico continuamente mis habilidades manuales.", "unidad": "Manada", "como_se_cumple": "Estimulando su imaginación y pensamiento lúdico al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo para resolver situaciones sencillas de forma creativa."}, {"id": "11320fb6-98de-4725-825d-db858e3bffa2", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Tropa", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo para superar los desafíos técnicos de la dinámica."}, {"id": "fd3d3e14-e92b-4ab5-8298-9018c6e70b20", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo para superar los desafíos técnicos de la dinámica."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Liderando iniciativas de servicio, diálogo intercultural y organización comunitaria al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, velando por la inclusión y el bienestar colectivo."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, fortaleciendo la convivencia democrática."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, fortaleciendo la convivencia democrática."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo con sus compañeros de seisena."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, fortaleciendo la convivencia democrática."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr velozmente transportando un vaso lleno de agua sobre la cabeza o una bandeja sin derramarlo, fortaleciendo la convivencia democrática."}]}'::jsonb WHERE id = 'd48a794f-c9c5-4799-a032-3654fda48aa1';
