UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["manada", "compañía", "tropa"], "objetivos": ["Desfogue de Energías", "Trabajo en equipo"], "materiales": ["Pañolin"], "variaciones": "Las variaciones se pueden hacer en el momento que la o el participante llega al punto de referencia (guiadora o dirigente) en ese lugar puede responder una pregunta, o hacer borrachitos, sapitos, ranitas, etc. pueden correr en una forma determinada y regresar de otra, etc.", "recomendaciones": "Procure hacer la actividad en un terreno plano, e idealmente suave, haga énfasis en la necesidad de una distancia segura entre una y otro participante que se encuentra en la fila para evitar que se pisen cuando pasen por encima.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CuerpoATierra.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga, trabajando en equipo y respetando sus límites corporales."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga, trabajando en equipo y respetando sus límites corporales."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga, trabajando en equipo y respetando sus límites corporales."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga, trabajando en equipo y respetando sus límites corporales."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga con sus compañeros de seisena."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga, fortaleciendo la convivencia democrática."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga, fortaleciendo la convivencia democrática."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga, fortaleciendo la convivencia democrática."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al arrojarse al suelo rápidamente al escuchar la señal de peligro y arrastrarse para cubrirse de la vista enemiga, fortaleciendo la convivencia democrática."}]}'::jsonb WHERE id = 'c35bbb99-0eeb-4bc0-8e2f-316fd8891f5a';
UPDATE public.articulos SET metadata = '{"areas": ["carácter", "creatividad", "sociabilidad"], "lugares": ["Exterior"], "cantidad": "04 participantes", "duracion": "01 hora", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Aprendizaje por la acción"], "materiales": ["Agua", "Fuego", "Fósforos", "Pala", "Palo"], "variaciones": "", "recomendaciones": "", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_tallerDeFogatas.png", "objetivos_educativos": [{"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Consolidando sus valores personales, coherencia ética y toma de decisiones firmes al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad, guiando a otros con el ejemplo."}, {"id": "770a8ff3-7bb8-45dd-b114-5ae1069eff62", "area": "Carácter", "texto": "Actúo consecuentemente con los valores que me inspiran.", "unidad": "Clan", "como_se_cumple": "Autoevaluando su coherencia de vida y templanza ante la presión al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad, reafirmando su compromiso con su proyecto personal y la Ley Scout."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad, actuando con honestidad y espíritu de superación."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad, actuando con honestidad y espíritu de superación."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad, actuando con honestidad y espíritu de superación."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad, actuando con honestidad y espíritu de superación."}, {"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayoría de los problemas técnicos domésticos simples.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando su agilidad mental, pensamiento crítico y capacidad de innovación al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad, liderando la resolución del problema."}, {"id": "29eee8b1-a414-4df9-90e1-520a384fb9aa", "area": "Creatividad", "texto": "Uno los conocimientos teórico y práctico mediante la aplicación constante de mis habilidades técnicas y manuales.", "unidad": "Clan", "como_se_cumple": "Diseñando estrategias complejas y adaptativas con plena autonomía al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad, demostrando versatilidad y madurez intelectual."}, {"id": "103661fc-3396-4eac-9182-58b7e54d5115", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad para superar los desafíos técnicos de la dinámica."}, {"id": "0f60be94-6de3-4c34-a6ff-5b5018f0b156", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad para superar los desafíos técnicos de la dinámica."}, {"id": "11320fb6-98de-4725-825d-db858e3bffa2", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Tropa", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad para superar los desafíos técnicos de la dinámica."}, {"id": "fd3d3e14-e92b-4ab5-8298-9018c6e70b20", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad para superar los desafíos técnicos de la dinámica."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Liderando iniciativas de servicio, diálogo intercultural y organización comunitaria al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad, velando por la inclusión y el bienestar colectivo."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo el servicio social, la justicia y la construcción de ciudadanía activa al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad, asumiendo un rol proactivo en su comunidad."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad, fortaleciendo la convivencia democrática."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad, fortaleciendo la convivencia democrática."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad, fortaleciendo la convivencia democrática."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al recolectar yesca y leña para construir y encender diferentes tipos de fogata bajo estrictas normas de seguridad, fortaleciendo la convivencia democrática."}]}'::jsonb WHERE id = 'efc4e885-84e0-4c93-a206-6b3c5f5635ff';
UPDATE public.articulos SET metadata = '{"areas": ["afectividad", "creatividad", "sociabilidad"], "lugares": ["Exterior", "Interior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "clan"], "objetivos": ["Construcción de Equipos", "Estimular la confianza", "Fomentar un entorno de confianza", "Trabajo en equipo"], "materiales": ["Lápiz", "Papel"], "variaciones": "", "recomendaciones": "", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Desarrolla el autoconocimiento, la confianza grupal y la empatía en las interacciones del juego. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_LaIslaDesierta.png", "objetivos_educativos": [{"id": "81298790-d245-48c6-8b1b-266b218c69da", "area": "Afectividad", "texto": "Me esfuerzo por encontrar mi identidad personal.", "unidad": "Avanzada", "como_se_cumple": "Estableciendo vínculos de confianza, madurez afectiva y comunicación asertiva al debatir en grupo qué herramientas u objetos limitados llevar a una isla desierta para garantizar la supervivencia, manejando constructivamente la frustración."}, {"id": "07d61bf7-36fc-40f6-8f8e-21fe97b169f0", "area": "Afectividad", "texto": "Logro y mantengo un estado interior de libertad, equilibrio y madurez emocional.", "unidad": "Clan", "como_se_cumple": "Integrando la madurez emocional y la resiliencia en sus relaciones interpersonales al debatir en grupo qué herramientas u objetos limitados llevar a una isla desierta para garantizar la supervivencia, promoviendo un clima grupal de apoyo y contención."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando su agilidad mental, pensamiento crítico y capacidad de innovación al debatir en grupo qué herramientas u objetos limitados llevar a una isla desierta para garantizar la supervivencia, liderando la resolución del problema."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Diseñando estrategias complejas y adaptativas con plena autonomía al debatir en grupo qué herramientas u objetos limitados llevar a una isla desierta para garantizar la supervivencia, demostrando versatilidad y madurez intelectual."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Liderando iniciativas de servicio, diálogo intercultural y organización comunitaria al debatir en grupo qué herramientas u objetos limitados llevar a una isla desierta para garantizar la supervivencia, velando por la inclusión y el bienestar colectivo."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo el servicio social, la justicia y la construcción de ciudadanía activa al debatir en grupo qué herramientas u objetos limitados llevar a una isla desierta para garantizar la supervivencia, asumiendo un rol proactivo en su comunidad."}]}'::jsonb WHERE id = '4ac6da05-a5c8-43a7-921b-e2af3a956aa9';
UPDATE public.articulos SET metadata = '{"areas": ["carácter", "sociabilidad"], "lugares": ["Exterior", "Interior"], "cantidad": "individual", "duracion": "20 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "descargas": [{"url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_DinamicaComoSeguirInstrucciones.pdf", "nombre": "Documento Adjunto - Hoja de Actividad"}], "objetivos": ["Aprender a seguir instrucciones", "Estimular la atención a los detalles", "Reforzar el poner atención"], "materiales": ["Lápiz", "Papel", "Hoja con instrucciones"], "variaciones": "Puede cambiar las pruebas en la hoja para hacerlas más divertidas y distender un poco más el ambiente, cosas como por ejemplo salte en un pie, cante una canción mientras se toca el estomago en círculos, etc.", "recomendaciones": "Para facilitar la dinámica es recomendable antes de entregar la hoja dada vuelta para el anverso y pedir que no la den vuelta hasta que se dé la indicación, al mismo tiempo que hace énfasis en que es una prueba con tiempo y pone en marcha su reloj con un cronómetro o algo que ejerza presión de tiempo sobre los participantes.", "justificacion_areas": "Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_DinamicaComoSeguirInstrucciones.png", "objetivos_educativos": [{"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Consolidando sus valores personales, coherencia ética y toma de decisiones firmes al ejecutar una lista de acciones escritas paso a paso, prestando atención a las trampas de lectura rápida, guiando a otros con el ejemplo."}, {"id": "770a8ff3-7bb8-45dd-b114-5ae1069eff62", "area": "Car