UPDATE public.articulos SET metadata = '{"areas": ["carácter", "corporalidad", "creatividad", "sociabilidad"], "lugares": ["Bosque", "Exterior"], "cantidad": "04 participantes", "duracion": "40 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Estimular la observación", "Perder el miedo a la oscuridad", "Promover la elaboración de estrategias", "Trabajo en equipo"], "materiales": ["Fósforos", "Linterna", "Velas"], "variaciones": "", "recomendaciones": "Enfatizar la necesidad de ser sigilosos y estratégicos.¿Ajustar la dificultad según la edad y habilidades de los participantes. Procure enfatizar caminar con cuidado en la oscuridad para evitar accidentes.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_misionNocturnaAcechoYSigilo.png", "objetivos_educativos": [{"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Consolidando sus valores personales, coherencia ética y toma de decisiones firmes al moverse sigilosamente en la oscuridad para infiltrarse en una base sin ser iluminado por las linternas, guiando a otros con el ejemplo."}, {"id": "770a8ff3-7bb8-45dd-b114-5ae1069eff62", "area": "Carácter", "texto": "Actúo consecuentemente con los valores que me inspiran.", "unidad": "Clan", "como_se_cumple": "Autoevaluando su coherencia de vida y templanza ante la presión al moverse sigilosamente en la oscuridad para infiltrarse en una base sin ser iluminado por las linternas, reafirmando su compromiso con su proyecto personal y la Ley Scout."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al moverse sigilosamente en la oscuridad para infiltrarse en una base sin ser iluminado por las linternas, actuando con honestidad y espíritu de superación."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al moverse sigilosamente en la oscuridad para infiltrarse en una base sin ser iluminado por las linternas, actuando con honestidad y espíritu de superación."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al moverse sigilosamente en la oscuridad para infiltrarse en una base sin ser iluminado por las linternas, actuando con honestidad y espíritu de superación."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al moverse sigilosamente en la oscuridad para infiltrarse en una base sin ser iluminado por las linternas, actuando con honestidad y espíritu de superación."}, {"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Potenciando su rendimiento psicomotor, toma de decisiones rápidas y resistencia aeróbica al moverse sigilosamente en la oscuridad para infiltrarse en una base sin ser iluminado por las linternas, fomentando la autodisciplina y hábitos saludables."}, {"id": "106e27af-ec7a-45fa-9295-fcef88fbef3d", "area": "Corporalidad", "texto": "Convivo constantemente en la naturaleza y participo en actividades deportivas y recreativas.", "unidad": "Clan", "como_se_cumple": "Consolidando el dominio y autocontrol corporal, evaluando sus límites físicos e impulsos al moverse sigilosamente en la oscuridad para infiltrarse en una base sin ser iluminado por las linternas con un sentido de superación constante."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al moverse sigilosamente en la oscuridad para infiltrarse en una base sin ser iluminado por las linternas, trabajando en equipo y respetando sus límites corporales."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al moverse sigilosamente en la oscuridad para infiltrarse en una base sin ser iluminado por las linternas, trabajando en equipo y respetando sus límites corporales."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al moverse sigilosamente en la oscuridad para infiltrarse en una base sin ser iluminado por las linternas, trabajando en equipo y respetando sus límites corporales."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa."