UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "carácter"], "lugares": ["Campo Abierto", "Exterior", "Interior", "Sala"], "cantidad": "05 participantes", "duracion": "15 minutos", "unidades": ["manada"], "objetivos": ["Desarrollar la motricidad", "Estimular la creatividad", "Refuerzo de habilidades físicas", "Trabajo en equipo"], "materiales": ["Pañolin"], "variaciones": "Esta actividad también se puede realizar simplemente tomándose de las manos con los ojos vendados o cerrados y realizando también el mismo proceso de desenredar el círculo.", "recomendaciones": "<ul>\r\n \t<li>Revisar el Lugar a realizar la actividad.</li>\r\n \t<li>Mantener la atención durante el desarrollo del juego con el fin de evitar accidentes.</li>\r\n</ul>", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_Enredados.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al pasar el cuerpo a través de una telaraña de cuerdas con cascabeles sin tocarlas para evitar que suenen, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al pasar el cuerpo a través de una telaraña de cuerdas con cascabeles sin tocarlas para evitar que suenen, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "ec280dd0-2d80-4b84-86ad-2d362da14886", "area": "Creatividad", "texto": "Me gusta participar en juegos de observación.", "unidad": "Manada", "como_se_cumple": "Estimulando su imaginación y pensamiento lúdico al pasar el cuerpo a través de una telaraña de cuerdas con cascabeles sin tocarlas para evitar que suenen para resolver situaciones sencillas de forma creativa."}, {"id": "418f2b77-f15b-405a-95bd-8033c0b6a4c2", "area": "Creatividad", "texto": "Puedo contar con detalles las anécdotas y aventuras que hemos tenido en la Manada.", "unidad": "Manada", "como_se_cumple": "Estimulando su imaginación y pensamiento lúdico al pasar el cuerpo a través de una telaraña de cuerdas con cascabeles sin tocarlas para evitar que suenen para resolver situaciones sencillas de forma creativa."}, {"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Asumiendo con alegría su rol en el juego al pasar el cuerpo a través de una telaraña de cuerdas con cascabeles sin tocarlas para evitar que suenen, aprendiendo a esforzarse por el grupo y a aceptar los resultados."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Asumiendo con alegría su rol en el juego al pasar el cuerpo a través de una telaraña de cuerdas con cascabeles sin tocarlas para evitar que suenen, aprendiendo a esforzarse por el grupo y a aceptar los resultados."}]}'::jsonb WHERE id = 'fd254b06-1ce1-46e1-bbcd-631170b07f1b';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "clan", "compañía", "manada", "tropa"], "objetivos": ["Crear un ambiente de distensión", "Estimular la creatividad", "Trabajo en equipo"], "materiales": ["Agua", "Vasos plásticos o de papel"], "variaciones": "Puede variar la actividad traspasando el vaso por entre la piernas de las o los participantes. O si tiene pocos vasos sÉlo traspasando el vaso completo de un participante a otro.", "recomendaciones": "Procure utilizar una superficie que no se vuelva resbalosa con la caída de agua.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_UnVasoDeLecheParaSanta.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Potenciando su rendimiento psicomotor, toma de decisiones rápidas y resistencia aeróbica al trasladar leche (agua coloreada) en un vaso sorteando obstáculos con movimientos coordinados, fomentando la autodisciplina y hábitos saludables."}, {"id": "106e27af-ec7a-45fa-9295-fcef88fbef3d", "area": "Corporalidad", "texto": "Convivo constantemente en la naturaleza y participo en actividades deportivas y recreativas.", "unidad": "Clan", "como_se_cumple": "Consolidando el dominio y autocontrol corporal, evaluando sus límites físicos e impulsos al trasladar leche (agua coloreada) en un vaso sorteando obstáculos con movimientos coordinados con un sentido de superación constante."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al trasladar leche (agua coloreada) en un vaso sorteando obstáculos con movimientos coordinados, trabajando en equipo y respetando sus límites corporales."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al trasladar leche (agua coloreada) en un vaso sorteando obstáculos con movimientos coordinados, trabajando en equipo y respetando sus límites corporales."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al trasladar leche (agua coloreada) en un vaso sorteando obstáculos con movimientos coordinados, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "5d2d48ed-c461-4a8e-9048-cceecd3de2e2", "area": "Corporalidad", "texto": "Me gusta jugar con otros niños y niñas y respeto las reglas de los juegos.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al trasladar leche (agua coloreada) en un vaso sorteando obstáculos con movimientos coordinados, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al trasladar leche (agua coloreada) en un vaso sorteando obstáculos con movimientos coordinados, trabajando en equipo y respetando sus límites corporales."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al trasladar leche (agua coloreada) en un vaso sorteando obstáculos con movimientos coordinados, trabajando en equipo y respetando sus límites corporales."}, {"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayoría de los problemas técnicos domésticos simples.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando su agilidad mental, pensamiento crítico y capacidad de innovación al trasladar leche (agua coloreada) en un vaso sorteando obstáculos con movimientos coordinados, liderando la resolución del problema."}, {"id": "29eee8b1-a414-4df9-90e1-520a384fb9aa", "area": "Creatividad", "texto": "Uno los conocimientos teórico y práctico mediante la aplicación constante de mis habilidades técnicas y manuales.", "unidad": "Clan", "como_se_cumple": "Diseñando estrategias complejas y adaptativas con plena autonomía al trasladar leche (agua coloreada) en un vaso sorteando obstáculos con movimientos coordinados, demostrando versatilidad y madurez intelectual."}, {"id": "103661fc-3396-4eac-9182-58b7e54d5115", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al trasladar leche (agua coloreada) en un vaso sorteando obstáculos con movimientos coordinados para superar los desafíos técnicos de la dinámica."}, {"id": "0f60be94-6de3-4c34-a6ff-5b5018f0b156", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Compañí