UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Aprendizaje por la acción", "Desarrollar la motricidad"], "materiales": ["Fósforos"], "variaciones": "Puede variar la actividad utilizando una vela que tendrá un efecto similar.", "recomendaciones": "Procure tomar todas la precauciones de seguridad posibles, primero no realice la actividad en un área boscosa, idealmente sólo realícela en un área cubierta por cemento y siempre tenga agua a la mano para evitar un incendio.\r\n\r\nHaga las indicaciones necesarias a los participantes sobre le el cuidado y los peligros del fuego.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_carreraDeFosforos.png", "objetivos_educativos": [{"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Potenciando su rendimiento psicomotor, toma de decisiones rápidas y resistencia aeróbica al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento, fomentando la autodisciplina y hábitos saludables."}, {"id": "69fff91f-a493-483d-92d6-8319700236c2", "area": "Corporalidad", "texto": "Conozco los procesos biológicos que regulan mi organismo, protejo mi salud, acepto mis posibilidades físicas y oriento mis impulsos y fuerzas.", "unidad": "Clan", "como_se_cumple": "Consolidando el dominio y autocontrol corporal, evaluando sus límites físicos e impulsos al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento con un sentido de superación constante."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento, trabajando en equipo y respetando sus límites corporales."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento, trabajando en equipo y respetando sus límites corporales."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento, trabajando en equipo y respetando sus límites corporales."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento, trabajando en equipo y respetando sus límites corporales."}, {"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayoría de los problemas técnicos domésticos simples.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando su agilidad mental, pensamiento crítico y capacidad de innovación al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento, liderando la resolución del problema."}, {"id": "29eee8b1-a414-4df9-90e1-520a384fb9aa", "area": "Creatividad", "texto": "Uno los conocimientos teórico y práctico mediante la aplicación constante de mis habilidades técnicas y manuales.", "unidad": "Clan", "como_se_cumple": "Diseñando estrategias complejas y adaptativas con plena autonomía al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento, demostrando versatilidad y madurez intelectual."}, {"id": "103661fc-3396-4eac-9182-58b7e54d5115", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento para superar los desafíos técnicos de la dinámica."}, {"id": "0f60be94-6de3-4c34-a6ff-5b5018f0b156", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento para superar los desafíos técnicos de la dinámica."}, {"id": "11320fb6-98de-4725-825d-db858e3bffa2", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Tropa", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento para superar los desafíos técnicos de la dinámica."}, {"id": "fd3d3e14-e92b-4ab5-8298-9018c6e70b20", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al encender un fósforo y mantenerlo prendido el mayor tiempo posible a la intemperie aplicando técnicas de viento para superar los desafíos técnicos de la dinámica."}]}'::jsonb WHERE id = '25e55b5d-8f37-40af-9d43-ba0c4f3b74fd';
UPDATE public.articulos SET metadata = '{"areas": ["creatividad", "espiritualidad"], "lugares": ["Exterior", "Interior"], "cantidad": "individual", "duracion": "20 minutos", "unidades": ["avanzada", "clan"], "descargas": [{"url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElEpitafio.pdf", "nombre": "Documento Adjunto - Hoja de Epitafio"}], "objetivos": ["Estimular el pensamiento crítico", "Estimular la reflexión"], "materiales": ["Lápiz", "Papel"], "variaciones": "Puede agregar una temática particular a los epitafios, por ejemplo, haciendo la pregunta ¿Qué diría su epitafio si usted fuera Bombero? o agregando cualquier otra circunstancia específica para ayudar a reflexionar sobre un trabajo en particular.", "recomendaciones": "Trate de generar o esperar a que se de el ambiente reflexivo adecuado para la actividad, esta es una actividad de introspección para jóvenes que en algunos casos puede generar sensibilidades.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Conecta a los participantes con la creación y el sentido de trascendencia espiritual de la hermandad scout.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElEpitafio.png", "objetivos_educativos": [{"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando su agilidad mental, pensamiento crítico y capacidad de innovación al redactar un epitafio o reflexión profunda sobre el legado y la huella personal que se desea dejar en la vida, liderando la resolución del problema."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Diseñando estrategias complejas y adaptativas con plena autonomía al redactar un epitafio o reflexión profunda sobre el legado y la huella personal que se desea dejar en la vida, demostrando versatilidad y madurez intelectual."}, {"id": "c165a639-f87a-4f6c-a637-69894848b507", "area": "Espiritualidad", "texto": "Respeto y cuido la naturaleza porque me siento responsable de la obra creadora de Dios.", "unidad": "Avanzada", "como_se_cumple": "Profundizando en sus convicciones de fe, coherencia espiritual y respeto por la diversidad de creencias al redactar un epitafio o reflexión profunda sobre el legado y la huella personal que se desea dejar en la vida de forma comunitaria."}, {"id": "0a9a9dac-0b1c-4f11-8600-291de10b1b95", "area": "Espiritualidad", "texto": "Busco siempre a Dios en forma personal y comunitaria, aprendiendo a reconocerlo en los hombres y en la Creación.", "unidad": "Clan", "como_se_cumple": "Viviendo su fe y espiritualidad de manera transformadora y comprometida al redactar un epitafio o reflexión profunda sobre el legado y la huella personal que se desea dejar en la vida, traduciendo sus valores en acciones concretas de servicio."}]}'::jsonb WHERE id = '18ae9052-19bf-48ca-89a3-c34f0081e7ca';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "05 participantes", "duracion": "15 minutos", "unidades": ["compañía", "manada", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Crear un ambiente de distensión", "Desfogue de Energías", "Refuerzo de habilidades físicas"], "materiales": ["Sin Materiales"], "variaciones": "Se puede hacer por equipos, donde gana el equipo que conserva más esquinas cuando termina el juego, sin embargo, para ello es necesario que haya más participantes en el centro.", "recomendaciones": "Tenga cuidado de elegir un terreno nivelado y de hacer énfasis en el respeto por los demás para que no se empujen a la hora de ver quién llega primero a tomar una esquina.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_TomaUnaEsquina.png", "objetivos_educativos": [{"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal, trabajando en equipo y respetando sus límites corporales."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal, trabajando en equipo y respetando sus límites corporales."}, {"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal, trabajando en equipo y respetando sus límites corporales."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal, trabajando en equipo y respetando sus límites corporales."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal, fortaleciendo la convivencia democrática."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal, fortaleciendo la convivencia democrática."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal con sus compañeros de seisena."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal, fortaleciendo la convivencia democrática."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al correr para posicionarse en una de las esquinas o bases marcadas cuando cesa la música o la señal, fortaleciendo la convivencia democrática."}]}'::jsonb WHERE id = '0e4290d8-a6c8-4bbb-94b6-7bee0aac8dc3';
UPDATE public.articulos SET metadata = '{"areas": ["sociabilidad"], "lugares": ["Campo delimitado", "Interior", "Sala"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["manada", "compañía", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Crear un ambiente de distensión", "Refuerzo de habilidades técnicas"], "materiales": ["Sin Materiales"], "variaciones": "Una variación para los más pequeños puede ser simplemente decir el número del lugar al azar, o cambiar el nombre de cada una de las esquinas por alguna actividad o historia que se haya contado antes.", "recomendaciones": "Utilice idealmente una sala de clases debido a que es más fácil para los más pequeños caminar sigilosamente, o adapte el lugar de acuerdo a las necesidades que tenga para desarrollar.", "justificacion_areas": "Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_AsesinoDeEsquinas.png", "objetivos_educativos": [{"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al descifrar a través de la observación guiada y el guiño de ojo quién es el ''asesino'' secreto del juego con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al descifrar a través de la observación guiada y el guiño de ojo quién es el ''asesino'' secreto del juego con sus compañeros de seisena."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al descifrar a través de la observación guiada y el guiño de ojo quién es el ''asesino'' secreto del juego, fortaleciendo la convivencia democrática."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al descifrar a través de la observación guiada y el guiño de ojo quién es el ''asesino'' secreto del juego, fortaleciendo la convivencia democrática."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al descifrar a través de la observación guiada y el guiño de ojo quién es el ''asesino'' secreto del juego, fortaleciendo la convivencia democrática."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al descifrar a través de la observación guiada y el guiño de ojo quién es el ''asesino'' secreto del juego, fortaleciendo la convivencia democrática."}]}'::jsonb WHERE id = 'e23ded89-7293-4b7f-941b-7509b43a745f';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "individual", "duracion": "15 minutos", "unidades": ["manada"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Estimular la creatividad"], "materiales": ["Palo", "Porotos"], "variaciones": "Se puede variar según el terreno, hacerlo individual o por equipos.", "recomendaciones": "Permita a los participantes utilizar la imaginación en el desplazamiento del poroto.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDePorotos.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al transportar porotos con una pajilla o cuchara de un extremo a otro en una prueba de motricidad fina, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al transportar porotos con una pajilla o cuchara de un extremo a otro en una prueba de motricidad fina, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "ec280dd0-2d80-4b84-86ad-2d362da14886", "area": "Creatividad", "texto": "Me gusta participar en juegos de observación.", "unidad": "Manada", "como_se_cumple": "Estimulando su imaginación y pensamiento lúdico al transportar porotos con una pajilla o cuchara de un extremo a otro en una prueba de motricidad fina para resolver situaciones sencillas de forma creativa."}, {"id": "418f2b77-f15b-405a-95bd-8033c0b6a4c2", "area": "Creatividad", "texto": "Puedo contar con detalles las anécdotas y aventuras que hemos tenido en la Manada.", "unidad": "Manada", "como_se_cumple": "Estimulando su imaginación y pensamiento lúdico al transportar porotos con una pajilla o cuchara de un extremo a otro en una prueba de motricidad fina para resolver situaciones sencillas de forma creativa."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al transportar porotos con una pajilla o cuchara de un extremo a otro en una prueba de motricidad fina con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al transportar porotos con una pajilla o cuchara de un extremo a otro en una prueba de motricidad fina con sus compañeros de seisena."}]}'::jsonb WHERE id = '73044568-1f54-4fa8-a79d-fe47fcd839a1';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "20 minutos", "unidades": ["manada", "compañía", "tropa", "avanzada"], "objetivos": ["Refuerzo de habilidades físicas", "Trabajo en equipo"], "materiales": ["Pañolin", "Tela"], "variaciones": "La carrera puede ser efectuada en parejas y haciendo relevos, de manera que cuando una pareja llega a un tramo, hay otra pareja esperando en ese punto para iniciar otro tramo y así sucesivamente hasta llegar a la meta.", "recomendaciones": "Ponga especial énfasis en que los jinetes deben ser llevados sobre la tela y en caso de que la fuerza de los \"Renos\" de su equipo haga que se levante sobre sus pies deben detenerse y esperar a que tome asiento el jinete y luego continuar desde el punto donde el jinete fue levantado.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElTrineodelViejitoPascuero.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos, trabajando en equipo y respetando sus límites corporales."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos, trabajando en equipo y respetando sus límites corporales."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos, trabajando en equipo y respetando sus límites corporales."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos, trabajando en equipo y respetando sus límites corporales."}, {"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Potenciando su rendimiento psicomotor, toma de decisiones rápidas y resistencia aeróbica al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos, fomentando la autodisciplina y hábitos saludables."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos con sus compañeros de seisena."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos, fortaleciendo la convivencia democrática."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos, fortaleciendo la convivencia democrática."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos, fortaleciendo la convivencia democrática."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos, fortaleciendo la convivencia democrática."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Liderando iniciativas de servicio, diálogo intercultural y organización comunitaria al arrastrar en equipo un trineo improvisado cargado de regalos o un compañero en una pista de relevos, velando por la inclusión y el bienestar colectivo."}]}'::jsonb WHERE id = 'e779b517-778a-40e7-a4cf-4531c257de03';
UPDATE public.articulos SET metadata = '{"areas": ["afectividad", "carácter", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "04 participantes", "duracion": "15 minutos", "unidades": ["compañía", "tropa"], "objetivos": ["Crear un ambiente de distensión", "Estimular el liderazgo", "Fomentar un entorno de confianza", "Trabajo en equipo"], "materiales": ["Pañolin"], "variaciones": "Existe una versión en parejas, donde se turnan en el trayecto de ida y de vuelta, esta versión esta más enfocada en generar lazos o relaciones entre las y los participantes más que en reforzar un liderazgo.", "recomendaciones": "Procure que el terreno no este muy accidentado para evitar caídas y observe meticulosamente el proceso para evaluar el liderazgo del guía de patrulla.", "justificacion_areas": "Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Desarrolla el autoconocimiento, la confianza grupal y la empatía en las interacciones del juego. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElLazarilloEnPatrulla.png", "objetivos_educativos": [{"id": "818d8a25-549b-4e01-a830-e50d73e39025", "area": "Afectividad", "texto": "Me doy cuenta y puedo hablar de las cosas que me atemorizan.", "unidad": "Compañía", "como_se_cumple": "Cultivando la empatía, el respeto mutuo y la asertividad al caminar en fila india a ciegas confiando plenamente en las indicaciones físicas del guía al frente, apoyando emocionalmente a los miembros de su patrulla."}, {"id": "67a2f0fa-9b1e-4b7b-bda2-e25696c87898", "area": "Afectividad", "texto": "Trato de dominar mis reacciones, aún en situaciones difíciles o inesperadas.", "unidad": "Compañía", "como_se_cumple": "Cultivando la empatía, el respeto mutuo y la asertividad al caminar en fila india a ciegas confiando plenamente en las indicaciones físicas del guía al frente, apoyando emocionalmente a los miembros de su patrulla."}, {"id": "03ccaf4c-03c4-42a8-b311-47fef60f204c", "area": "Afectividad", "texto": "Me doy cuenta y puedo hablar de las cosas que me atemorizan.", "unidad": "Tropa", "como_se_cumple": "Cultivando la empatía, el respeto mutuo y la asertividad al caminar en fila india a ciegas confiando plenamente en las indicaciones físicas del guía al frente, apoyando emocionalmente a los miembros de su patrulla."}, {"id": "74e6c7e0-f9f6-47d3-acdb-d6df315ef123", "area": "Afectividad", "texto": "Trato de dominar mis reacciones, aún en situaciones difíciles o inesperadas.", "unidad": "Tropa", "como_se_cumple": "Cultivando la empatía, el respeto mutuo y la asertividad al caminar en fila india a ciegas confiando plenamente en las indicaciones físicas del guía al frente, apoyando emocionalmente a los miembros de su patrulla."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al caminar en fila india a ciegas confiando plenamente en las indicaciones físicas del guía al frente, actuando con honestidad y espíritu de superación."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al caminar en fila india a ciegas confiando plenamente en las indicaciones físicas del guía al frente, actuando con honestidad y espíritu de superación."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al caminar en fila india a ciegas confiando plenamente en las indicaciones físicas del guía al frente, a