UPDATE public.articulos SET metadata = '{"areas": ["carácter", "corporalidad", "creatividad", "sociabilidad"], "lugares": ["Bosque", "Cerro", "Exterior", "Montaña"], "cantidad": "04 participantes", "duracion": "45 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Desarrollar la motricidad", "Estrategia y planificación", "Perder el miedo a la oscuridad", "Promover la elaboración de estrategias", "Trabajo en equipo"], "materiales": ["Reloj despertador"], "variaciones": "Los guardianes pueden eliminar algún saboteador quitándole el pañolín en modo acecho.\r\n\r\nSi el saboteador se da cuenta de la presencia del guardián, este debe volver a esconderse e volver a intentar sacarle el pañolín en otra ocasión u a otro saboteador.", "recomendaciones": "Deje claro que esta es una actividad donde lo que importa es la observación y el acecho por sobre los movimientos bruscos y rápidos, esto para evitar que se coloquen a correr y se generen accidentes, ya que el mejor lugar para hacer la actividad es un bosque sinuoso y con muchos lugares para ocultarse.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_BombaDeTiempo.png", "objetivos_educativos": [{"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Consolidando sus valores personales, coherencia ética y toma de decisiones firmes al desactivar un artefacto simulado al resolver una serie de acertijos de lógica antes de que expire el tiempo, guiando a otros con el ejemplo."}, {"id": "770a8ff3-7bb8-45dd-b114-5ae1069eff62", "area": "Carácter", "texto": "Actúo consecuentemente con los valores que me inspiran.", "unidad": "Clan", "como_se_cumple": "Autoevaluando su coherencia de vida y templanza ante la presión al desactivar un artefacto simulado al resolver una serie de acertijos de lógica antes de que expire el tiempo, reafirmando su compromiso con su proyecto personal y la Ley Scout."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al desactivar un artefacto simulado al resolver una serie de acertijos de lógica antes de que expire el tiempo, actuando con honestidad y espíritu de superación."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al desactivar un artefacto simulado al resolver una serie de acertijos de lógica antes de que expire el tiempo, actuando con honestidad y espíritu de superación."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al desactivar un artefacto simulado al resolver una serie de acertijos de lógica antes de que expire el tiempo, actuando con honestidad y espíritu de superación."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al desactivar un artefacto simulado al resolver una serie de acertijos de lógica antes de que expire el tiempo, actuando con honestidad y espíritu de superación."}, {"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Potenciando su rendimiento psicomotor, toma de decisiones rápidas y resistencia aeróbica al desactivar un artefacto simulado al resolver una serie de acertijos de lógica antes de que expire el tiempo, fomentando la autodisciplina y hábitos saludables."}, {"id": "69fff91f-a493-483d-92d6-8319700236c2", "area": "Corporalidad", "texto": "Conozco los procesos biológicos que regulan mi organismo, protejo mi salud, acepto mis posibilidades físicas y oriento mis impulsos y fuerzas.", "unidad": "Clan", "como_se_cumple": "Consolidando el dominio y autocontrol corporal, evaluando sus límites físicos e impulsos al desactivar un artefacto simulado al resolver una serie de acertijos de lógica antes de que expire el tiempo con un sentido de superación constante."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al desactivar un artefacto simulado al resolver una serie de acertijos de lógica antes de que expire el tiempo, trabajando en equipo y respetando sus límites corporales."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al desactivar un artefacto simulado al resolver una serie de acertijos de lógica antes de que expire el tiempo, trabajando en equipo y respetando sus límites corporales."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "co