UPDATE public.articulos SET metadata = '{"areas": ["carácter", "creatividad", "sociabilidad"], "lugares": ["Exterior", "Interior", "Sala"], "cantidad": "04 participantes", "duracion": "01 hora", "unidades": ["manada", "compañía", "tropa", "avanzada", "clan"], "objetivos": ["Estimular el pensamiento crítico", "Estimular la participación", "Fomentar el desarrollo del criterio", "Toma de Decisiones"], "materiales": ["Martillo de Juicio"], "variaciones": "Se pueden hacer adaptaciones a los procesos judiciales de cada país con el fin de también facilitar el conocimiento sobre el proceso judicial.", "recomendaciones": "Procure ser acotado con los tiempos de presentación y defensa para no sobre extender la actividad, de la misma manera procure generar un clima de solemnidad y respeto por los demás.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_JuegoDemocraticoJuicioEnLaCorte.png", "objetivos_educativos": [{"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Asumiendo con alegría su rol en el juego al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia, aprendiendo a esforzarse por el grupo y a aceptar los resultados."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Asumiendo con alegría su rol en el juego al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia, aprendiendo a esforzarse por el grupo y a aceptar los resultados."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia, actuando con honestidad y espíritu de superación."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia, actuando con honestidad y espíritu de superación."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia, actuando con honestidad y espíritu de superación."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia, actuando con honestidad y espíritu de superación."}, {"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Consolidando sus valores personales, coherencia ética y toma de decisiones firmes al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia, guiando a otros con el ejemplo."}, {"id": "770a8ff3-7bb8-45dd-b114-5ae1069eff62", "area": "Carácter", "texto": "Actúo consecuentemente con los valores que me inspiran.", "unidad": "Clan", "como_se_cumple": "Autoevaluando su coherencia de vida y templanza ante la presión al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia, reafirmando su compromiso con su proyecto personal y la Ley Scout."}, {"id": "ec280dd0-2d80-4b84-86ad-2d362da14886", "area": "Creatividad", "texto": "Me gusta participar en juegos de observación.", "unidad": "Manada", "como_se_cumple": "Estimulando su imaginación y pensamiento lúdico al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia para resolver situaciones sencillas de forma creativa."}, {"id": "418f2b77-f15b-405a-95bd-8033c0b6a4c2", "area": "Creatividad", "texto": "Puedo contar con detalles las anécdotas y aventuras que hemos tenido en la Manada.", "unidad": "Manada", "como_se_cumple": "Estimulando su imaginación y pensamiento lúdico al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia para resolver situaciones sencillas de forma creativa."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia para superar los desafíos técnicos de la dinámica."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia para superar los desafíos técnicos de la dinámica."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia para superar los desafíos técnicos de la dinámica."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia para superar los desafíos técnicos de la dinámica."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando su agilidad mental, pensamiento crítico y capacidad de innovación al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia, liderando la resolución del problema."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Diseñando estrategias complejas y adaptativas con plena autonomía al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia, demostrando versatilidad y madurez intelectual."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al asumir roles de defensa, fiscalía y jurado para debatir y juzgar un caso simulado con justicia con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area"