UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Exterior", "Interior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "compañía", "manada", "tropa"], "objetivos": ["Conocer las capacidades corporales", "Crear un ambiente de distensión", "Estimular la confianza", "Estimular la creatividad", "Fomentar un entorno de confianza"], "materiales": ["Sin Materiales"], "variaciones": "También se puede realizar con el escultor con los ojos vendados, para agregar dificultad.", "recomendaciones": "Procure dar indicaciones sobre el cuidado y el respeto del cuerpo de los demás.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_escultores.png", "objetivos_educativos": [{"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Potenciando su rendimiento psicomotor, toma de decisiones rápidas y resistencia aeróbica al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas, fomentando la autodisciplina y hábitos saludables."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al moldear el cuerpo de sus compañeros como si fueran arcilla para representar emociones, conceptos o escenas, trabajando en equipo y respetando sus límites corporales."}