UPDATE public.articulos SET metadata = '{"areas": ["carácter", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "04 participantes", "duracion": "15 minutos", "unidades": ["compañía", "manada", "tropa"], "objetivos": ["Perder el miedo a la oscuridad", "Reforzar lazos sociales", "Trabajo en equipo"], "materiales": ["Sin Materiales"], "variaciones": "", "recomendaciones": "", "justificacion_areas": "Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_lasSardinas.png", "objetivos_educativos": [{"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al buscar a un jugador escondido en la oscuridad; al encontrarlo, el buscador debe esconderse junto a él en el mismo espacio, actuando con honestidad y espíritu de superación."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Fortaleciendo su lealtad, autoconfianza y compromiso con su patrulla al buscar a un jugador escondido en la oscuridad; al encontrarlo, el buscador debe esconderse junto a él en el mismo espacio, actuando con honestidad y espíritu de superación."}, {"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Asumiendo con alegría su rol en el juego al buscar a un jugador escondido en la oscuridad; al encontrarlo, el buscador debe esconderse junto a él en el mismo espacio, aprendiendo a esforzarse por el grupo y a aceptar los resultados."}, {"id": "506b75