UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["manada", "compañía", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Trabajo en equipo"], "materiales": ["Sin Materiales"], "variaciones": "Una variación puede ser que si un equipo se llega a desarmar debe volver al punto de partida.", "recomendaciones": "Puede indicar que los elefantes emiten sonido y por lo mismo cada equipo debe hacer sonidos de elefantes mientras avanza.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeElefantes.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al correr a cuatro patas balanceando un brazo como trompa para empujar una pelota hasta la meta, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al correr a cuatro patas balanceando un brazo como trompa para empujar una pelota hasta la meta, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañí