UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad"], "lugares": ["Bosque", "Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "45 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Desarrollar la motricidad", "Estimular la observación", "Promover la elaboración de estrategias"], "materiales": ["Linterna"], "variaciones": "Una variación puede ser eliminar a las y los participantes cuando son descubiertos al avanzar.", "recomendaciones": "Tenga en consideración la iluminación en el lugar a la hora de jugar, prefiera un área boscosa para facilitar la huida de los prisioneros o un claro para dificultarla.\r\n\r\nHaga las recomendaciones de seguridad necesarias para que caminen con cuidado en un terreno sin iluminación.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_ElGuardiaYLosPrisioneros.png", "objetivos_educativos": [{"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Potenciando su rendimiento psicomotor, toma de decisiones rápidas y resistencia aeróbica al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia, fomentando la autodisciplina y hábitos saludables."}, {"id": "69fff91f-a493-483d-92d6-8319700236c2", "area": "Corporalidad", "texto": "Conozco los procesos biológicos que regulan mi organismo, protejo mi salud, acepto mis posibilidades físicas y oriento mis impulsos y fuerzas.", "unidad": "Clan", "como_se_cumple": "Consolidando el dominio y autocontrol corporal, evaluando sus límites físicos e impulsos al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia con un sentido de superación constante."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia, trabajando en equipo y respetando sus límites corporales."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia, trabajando en equipo y respetando sus límites corporales."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia, trabajando en equipo y respetando sus límites corporales."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al rescatar a los prisioneros de una celda vigilada distrayendo al guardia mediante sigilo y astucia, trabajando en equipo y respetando sus límites corporales."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando su agilidad mental, pensamiento cr