UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "05 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "compañía", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Desfogue de Energías", "Promover la elaboración de estrategias"], "materiales": ["Sin Materiales"], "variaciones": "Para iniciar el bulldog puede ser uno de los animadores de la actividad y este se retirara del centro del campo del juego cuando ya considere que hay suficientes \"bulldogs\".", "recomendaciones": "Sea claro y está atento a los que se salgan de los límites del campo.\r\n\r\nMucha gente siendo \"Bulldog\" puede causar accidentes, procure mantener un número razonable en el centro del campo de juego.\r\n\r\nHaga énfasis en el cuidado del cuerpo propio y de los demás, esta es una actividad muy física que puede causar accidentes cuando hay mucho entusiasmo en los participantes.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_BulldogIngles.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Potenciando su rendimiento psicomotor, toma de decisiones rápidas y resistencia aeróbica al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado, fomentando la autodisciplina y hábitos saludables."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado, trabajando en equipo y respetando sus límites corporales."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado, trabajando en equipo y respetando sus límites corporales."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado, trabajando en equipo y respetando sus límites corporales."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado, trabajando en equipo y respetando sus límites corporales."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Liderando iniciativas de servicio, diálogo intercultural y organización comunitaria al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado, velando por la inclusión y el bienestar colectivo."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado, fortaleciendo la convivencia democrática."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado, fortaleciendo la convivencia democrática."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado, fortaleciendo la convivencia democrática."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado, fortaleciendo la convivencia democrática."}]}'::jsonb WHERE id = '227840aa-8ae7-42ea-84ae-2e9ba40106a1';
UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "clan", "compañía", "manada", "tropa"], "objetivos": ["Crear un ambiente de distensión", "Estimular la creatividad", "Trabajo en equipo"], "materiales": ["Agua", "Vasos plásticos o de papel"], "variaciones": "Puede variar la actividad traspasando el vaso por entre la piernas de las o los participantes. O si tiene pocos vasos sólo traspasando el vaso completo de un participante a otro.", "recomendaciones": "Procure utilizar una superficie que no se vuelva resbalosa con la caída de agua.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_relevosDelVaso.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Potenciando su rendimiento psicomotor, toma de decisiones rápidas y resistencia aeróbica al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, fomentando la autodisciplina y hábitos saludables."}, {"id": "106e27af-ec7a-45fa-9295-fcef88fbef3d", "area": "Corporalidad", "texto": "Convivo constantemente en la naturaleza y participo en actividades deportivas y recreativas.", "unidad": "Clan", "como_se_cumple": "Consolidando el dominio y autocontrol corporal, evaluando sus límites físicos e impulsos al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca con un sentido de superación constante."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, trabajando en equipo y respetando sus límites corporales."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, trabajando en equipo y respetando sus límites corporales."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "5d2d48ed-c461-4a8e-9048-cceecd3de2e2", "area": "Corporalidad", "texto": "Me gusta jugar con otros niños y niñas y respeto las reglas de los juegos.", "unidad": "Manada", "como_se_cumple": "Ejercitando su coordinación y destrezas motrices al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, promoviendo el conocimiento y cuidado de su propio cuerpo mediante el juego."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, trabajando en equipo y respetando sus límites corporales."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Desafiando sus habilidades físicas, agilidad y resistencia al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, trabajando en equipo y respetando sus límites corporales."}, {"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayoría de los problemas técnicos domésticos simples.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando su agilidad mental, pensamiento crítico y capacidad de innovación al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, liderando la resolución del problema."}, {"id": "29eee8b1-a414-4df9-90e1-520a384fb9aa", "area": "Creatividad", "texto": "Uno los conocimientos teórico y práctico mediante la aplicación constante de mis habilidades técnicas y manuales.", "unidad": "Clan", "como_se_cumple": "Diseñando estrategias complejas y adaptativas con plena autonomía al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, demostrando versatilidad y madurez intelectual."}, {"id": "103661fc-3396-4eac-9182-58b7e54d5115", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca para superar los desafíos técnicos de la dinámica."}, {"id": "0f60be94-6de3-4c34-a6ff-5b5018f0b156", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca para superar los desafíos técnicos de la dinámica."}, {"id": "8985ff05-ee84-4fba-af46-146c5374df89", "area": "Creatividad", "texto": "Participo en los talleres de manualidades que se hacen en la Manada.", "unidad": "Manada", "como_se_cumple": "Estimulando su imaginación y pensamiento lúdico al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca para resolver situaciones sencillas de forma creativa."}, {"id": "d4232b99-5655-49c6-9d24-099cfe9c8180", "area": "Creatividad", "texto": "Practico continuamente mis habilidades manuales.", "unidad": "Manada", "como_se_cumple": "Estimulando su imaginación y pensamiento lúdico al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca para resolver situaciones sencillas de forma creativa."}, {"id": "11320fb6-98de-4725-825d-db858e3bffa2", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Tropa", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca para superar los desafíos técnicos de la dinámica."}, {"id": "fd3d3e14-e92b-4ab5-8298-9018c6e70b20", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca para superar los desafíos técnicos de la dinámica."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Liderando iniciativas de servicio, diálogo intercultural y organización comunitaria al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, velando por la inclusión y el bienestar colectivo."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo el servicio social, la justicia y la construcción de ciudadanía activa al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, asumiendo un rol proactivo en su comunidad."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, fortaleciendo la convivencia democrática."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, fortaleciendo la convivencia democrática."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca con sus compañeros de seisena."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma fraterna al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca con sus compañeros de seisena."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, fortaleciendo la convivencia democrática."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Cooperando activamente en la distribución de tareas y toma de decisiones de su patrulla al llenar un balde mediante relevos donde cada participante transporta un vaso de agua en la boca, fortaleciendo la convivencia democrática."}]}'::jsonb WHERE id = '2cde9fb7-221c-43ca-a7f0-a2057f4c57e1';
UPDATE public.articulos SET metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "30 minutos", "unidades": ["avanzada", "compañía", "tropa"], "objetivos": ["Promover la elaboración de estrategias", "Trabajo en equipo"], "materiales": ["Aguja", "Cartulina"], "variaciones": "La actividad se puede hacer con los ojos vendados, donde para llegar a la cartulina su equipo lo debe guiar con gritos y lo mismo al regresar, en este caso las perforaciones deben ser más grandes.", "recomendaciones": "A los dos grupos, es recomendable que tengan un cuaderno y lápiz donde puedan escribir lo que hayan descifrado con el tacto.\r\n\r\nProcure que el terreno de juego sea parejo para evitar accidentes de caídas.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_adivinaLaPalabra.png", "objetivos_educativos": [{"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Desarrollando su agilidad mental, pensamiento crítico y capacidad de innovación al adivinar palabras o términos scouts a través de mímica, gestos o descripciones sin nombrar palabras prohibidas, liderando la resolución del problema."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Proponiendo soluciones originales e ingeniosas con su patrulla al adivinar palabras o términos scouts a través de mímica, gestos o descripciones sin nombrar palabras prohibidas para superar los desafíos técnicos de 